// Build daily report and store in analytics table
const stats = $('Get Daily Stats').first().json;
const popular = $('Get Popular Items').all().map(i => i.json);
const restaurant = $('Get Active Restaurants').item.json;

const report = {
  restaurant_id: restaurant.id,
  restaurant_name: restaurant.name,
  date: new Date().toISOString().split('T')[0],
  total_orders: parseInt(stats.total_orders) || 0,
  total_revenue: parseFloat(stats.total_revenue) || 0,
  avg_order_value: parseFloat(stats.avg_order_value) || 0,
  delivered: parseInt(stats.delivered) || 0,
  cancelled: parseInt(stats.cancelled) || 0,
  bank_transfers: parseInt(stats.bank_transfers) || 0,
  cod_orders: parseInt(stats.cod_orders) || 0,
  popular_items: popular
};

return [{ json: report }];

// Format report as WhatsApp message for owner
const data = $('Build Report Data').first().json;

let msg = `📊 *Daily Report — ${data.date}*\n`;
msg += `🏪 ${data.restaurant_name}\n\n`;
msg += `📦 Total Orders: ${data.total_orders}\n`;
msg += `💰 Revenue: PKR ${data.total_revenue.toLocaleString()}\n`;
msg += `📈 Avg Order: PKR ${Math.round(data.avg_order_value)}\n`;
msg += `✅ Delivered: ${data.delivered}\n`;
msg += `❌ Cancelled: ${data.cancelled}\n\n`;
msg += `💳 Bank Transfers: ${data.bank_transfers}\n`;
msg += `💵 COD: ${data.cod_orders}\n\n`;

if (data.popular_items.length > 0) {
  msg += `🏆 *Top Items:*\n`;
  data.popular_items.forEach((item, i) => {
    msg += `${i + 1}. ${item.item_name} (${item.qty}x)\n`;
  });
}

msg += `\n---\nGenerated automatically at ${new Date().toLocaleTimeString()}`;

return [{ json: { message: msg, restaurant_id: data.restaurant_id } }];
